import { useMemo, useState } from "react";
import { DataGrid, type Column } from 'react-data-grid';
import 'react-data-grid/lib/styles.css';
import { useQuery, useQueries, useMutation, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import api from "@/api/app/client";
import { userService as accountService } from "@/api/auth/userService";
import { getApiErrorMessage } from "@/api/app/apiError";
import { Trash2, Check } from "lucide-react";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { PERMISSIONS } from "@/constants/permissions";
import type { Project, ProjectAssignment } from "@/types/project";
import type { User } from "@/types/user";
import type { Customer } from "@/types/customer";
import { HarmonyAlertDialog } from "@/components/ui/harmony-alert-dialog";
import { Button } from "@/shadcn/components/ui/button";

const extractList = (res: any): any[] => {
  const data = res?.data || res?.items || res;
  return Array.isArray(data) ? data : [];
};

const Assignments = () => {
  const queryClient = useQueryClient();
  const [selectedProject, setSelectedProject] = useState("");
  const [selectedEmployee, setSelectedEmployee] = useState("");
  const [startDate, setStartDate] = useState(new Date().toISOString().split("T")[0]);
  const [endDate, setEndDate] = useState("");
  const [assignmentToDelete, setAssignmentToDelete] = useState<{ projectId: string; assignmentId: string; name: string } | null>(null);
  const [assignmentToComplete, setAssignmentToComplete] = useState<{ projectId: string; assignmentId: string; name: string } | null>(null);

  const { data: projects = [] } = useQuery<Project[]>({
    queryKey: ["projects"],
    queryFn: () => api.get("/projects").then(r => extractList(r.data)),
  });

  const { data: employees = [] } = useQuery<User[]>({
    queryKey: ["employees"],
    queryFn: () => accountService.getEmployees().then(data => Array.isArray(data) ? data as User[] : []),
  });

  const { data: customers = [] } = useQuery<Customer[]>({
    queryKey: ["customers"],
    queryFn: () => api.get("/customers").then(r => extractList(r.data)),
  });

  const assignmentQueries = useQueries({
    queries: projects.map(p => ({
      queryKey: ["projects", p.id, "assignments"],
      queryFn: () => api.get(`/projects/${p.id}/assignments`).then(r => {
        const data = r.data.data || r.data;
        return Array.isArray(data) ? data as ProjectAssignment[] : [];
      }),
    })),
  });

  const assignmentsMap = useMemo(() => {
    return projects.reduce((acc, p, i) => {
      acc[p.id] = assignmentQueries[i]?.data ?? [];
      return acc;
    }, {} as Record<string, ProjectAssignment[]>);
  }, [projects, assignmentQueries]);

  const assignMutation = useMutation({
    mutationFn: ({ projectId, employeeId, startDate, endDate }: {
      projectId: string; employeeId: string; startDate: string; endDate: string | null;
    }) => api.post(`/projects/${projectId}/assignments`, {
      UserProfileId: employeeId,
      StartDate: startDate,
      EndDate: endDate || null,
    }),
    onSuccess: (_, { projectId }) => {
      queryClient.invalidateQueries({ queryKey: ["projects", projectId, "assignments"] });
      toast.success("Assigned successfully");
      setSelectedEmployee("");
      setSelectedProject("");
      setEndDate("");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Assignment failed")),
  });

  const completeMutation = useMutation({
    mutationFn: ({ projectId, assignmentId }: { projectId: string; assignmentId: string }) =>
      api.patch(`/projects/${projectId}/assignments/${assignmentId}/end`),
    onMutate: async ({ projectId, assignmentId }) => {
      await queryClient.cancelQueries({ queryKey: ["projects", projectId, "assignments"] });
      const previous = queryClient.getQueryData<ProjectAssignment[]>(["projects", projectId, "assignments"]);
      queryClient.setQueryData<ProjectAssignment[]>(["projects", projectId, "assignments"], old =>
        (old ?? []).map(a => a.id === assignmentId ? { ...a, endDate: new Date().toISOString() } : a)
      );
      return { previous, projectId };
    },
    onError: (err, _, context) => {
      if (context) queryClient.setQueryData(["projects", context.projectId, "assignments"], context.previous);
      toast.error(getApiErrorMessage(err, "Failed to complete assignment"));
    },
    onSuccess: () => setAssignmentToComplete(null),
    onSettled: (_, __, { projectId }) => {
      queryClient.invalidateQueries({ queryKey: ["projects", projectId, "assignments"] });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: ({ projectId, assignmentId }: { projectId: string; assignmentId: string }) =>
      api.delete(`/projects/${projectId}/assignments/${assignmentId}`),
    onMutate: async ({ projectId, assignmentId }) => {
      await queryClient.cancelQueries({ queryKey: ["projects", projectId, "assignments"] });
      const previous = queryClient.getQueryData<ProjectAssignment[]>(["projects", projectId, "assignments"]);
      queryClient.setQueryData<ProjectAssignment[]>(["projects", projectId, "assignments"], old =>
        (old ?? []).filter(a => a.id !== assignmentId)
      );
      return { previous, projectId };
    },
    onError: (err, _, context) => {
      if (context) queryClient.setQueryData(["projects", context.projectId, "assignments"], context.previous);
      toast.error(getApiErrorMessage(err, "Failed to remove assignment"));
    },
    onSuccess: () => setAssignmentToDelete(null),
    onSettled: (_, __, { projectId }) => {
      queryClient.invalidateQueries({ queryKey: ["projects", projectId, "assignments"] });
    },
  });

  const assign = () => {
    if (!selectedProject || !selectedEmployee) {
      toast.error("Please select both a project and an employee");
      return;
    }
    assignMutation.mutate({ projectId: selectedProject, employeeId: selectedEmployee, startDate, endDate: endDate || null });
  };

  const handleCompleteAssignment = (projectId: string, assignmentId: string, employeeName: string) => {
    setAssignmentToComplete({ projectId, assignmentId, name: employeeName });
  };

  const handleDeleteAssignment = (projectId: string, assignmentId: string) => {
    const assignment = assignmentsMap[projectId]?.find(a => a.id === assignmentId);
    const name = assignment ? getEmployeeName(assignment) : "this assignment";
    setAssignmentToDelete({ projectId, assignmentId, name });
  };

  const getEmployeeName = (assignment: any) => {
    const emp = employees.find(
      (e) => e.userProfileId === assignment.userProfileId || e.id === assignment.userProfileId
    );
    if (emp) {
      return emp.fullName || emp.name ||
        `${emp.firstName || ""} ${emp.lastName || ""}`.trim() ||
        emp.email || "Unknown";
    }
    return assignment.userProfileId?.slice(0, 8) + "..." || "Unknown";
  };

  const gridColumns: Column<any>[] = [
    { key: "customerName", name: "Customer Name", resizable: true },
    { key: "projectName", name: "Project Name", resizable: true },
    { key: "employeeName", name: "Employee Name", resizable: true },
    { key: "startDate", name: "Start Date", resizable: true },
    { key: "endDate", name: "End Date", resizable: true },
    {
      key: "actions",
      name: "Actions",
      width: 100,
      renderCell: ({ row }) => (
        <div className="flex justify-center gap-3 w-full items-center">
          {!row.rawAssignment.endDate && (
            <PermissionGate permission={PERMISSIONS.ProjectAssignment.Update} mode="disable">
              <span title="Mark as Completed" onClick={() => handleCompleteAssignment(row.projectId, row.assignmentId, row.employeeName)} className="cursor-pointer">
                <Check className="text-emerald-400 hover:text-emerald-300 transition-colors" />
              </span>
            </PermissionGate>
          )}
          <PermissionGate permission={PERMISSIONS.ProjectAssignment.Delete} mode="disable">
            <span title="Delete Assignment" onClick={() => handleDeleteAssignment(row.projectId, row.assignmentId)} className="cursor-pointer">
              <Trash2 className="text-destructive hover:text-destructive/80 transition-colors" />
            </span>
          </PermissionGate>
        </div>
      ),
    },
  ];

  const gridRows = useMemo(() => {
    const rows: any[] = [];
    projects.forEach((p) => {
      const customer = customers.find((c) => c.id === p.customerId);
      const customerName = customer ? customer.name : "N/A";
      const assignments = assignmentsMap[p.id] || [];
      assignments.forEach((a: any, index: number) => {
        rows.push({
          id: a.id || `${p.id}-${index}`,
          projectId: p.id,
          assignmentId: a.id,
          rawAssignment: a,
          customerName,
          projectName: p.name,
          employeeName: getEmployeeName(a),
          startDate: a.startDate ? new Date(a.startDate).toLocaleDateString() : "-",
          endDate: a.endDate ? new Date(a.endDate).toLocaleDateString() : "-",
        });
      });
    });
    return rows;
  }, [projects, customers, assignmentsMap, employees]);

  return (
    <div className="page-wrapper max-w-[1400px] mx-auto">
      <div className="page-header mb-8">
        <div>
          <h1 className="page-title text-3xl font-black tracking-tight text-foreground">Project Assignments</h1>
          <p className="page-subtitle text-muted-foreground font-medium">Manage and monitor employee-to-project resource allocations</p>
        </div>
      </div>

      {/* Assign Form Section */}
      <PermissionGate permission={PERMISSIONS.ProjectAssignment.Create} mode="disable">
        <div className="section-card p-0 mb-8 bg-card border border-border shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-border bg-muted/30 flex items-center justify-between">
            <h2 className="text-sm font-black uppercase tracking-widest text-muted-foreground">Resource Allocation Panel</h2>
            <div className="h-1.5 w-1.5 rounded-full bg-primary" />
          </div>

          <div className="p-8">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 items-end">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground px-1">Target Employee</label>
                <div className="relative">
                  <select
                    className="w-full bg-muted/50 border border-border rounded-xl px-4 py-2.5 text-sm font-semibold text-foreground outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all appearance-none"
                    value={selectedEmployee}
                    onChange={(e) => setSelectedEmployee(e.target.value)}
                  >
                    <option value="">Select Resource...</option>
                    {employees.map((emp) => {
                      const id = emp.userProfileId || emp.id || emp.userId || "";
                      const name = emp.fullName || emp.name ||
                        `${emp.firstName || ""} ${emp.lastName || ""}`.trim() ||
                        emp.email || id;
                      return <option key={id} value={id}>{name}</option>;
                    })}
                  </select>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground px-1">Project Assignment</label>
                <div className="relative">
                  <select
                    className="w-full bg-muted/50 border border-border rounded-xl px-4 py-2.5 text-sm font-semibold text-foreground outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all appearance-none"
                    value={selectedProject}
                    onChange={(e) => setSelectedProject(e.target.value)}
                  >
                    <option value="">Select Project...</option>
                    {projects.map((p) => (
                      <option key={p.id} value={p.id}>{p.name}</option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-muted-foreground px-1">Commencement Date</label>
                <input
                  type="date"
                  className="w-full bg-muted/50 border border-border rounded-xl px-4 py-2 text-sm font-semibold text-foreground outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all"
                  value={startDate}
                  onChange={(e) => setStartDate(e.target.value)}
                />
              </div>

              <Button className="w-full h-[42px]" onClick={assign} disabled={assignMutation.isPending}>
                <Check className="text-[10px]" />
                <span className="uppercase tracking-widest font-black text-xs">Execute Assignment</span>
              </Button>
            </div>
          </div>
        </div>
      </PermissionGate>

      {/* Grid Display Section */}
      <div className="section-card overflow-hidden bg-card border border-border shadow-sm rounded-2xl">
        <div className="px-6 py-5 border-b border-border flex justify-between items-center bg-muted/30">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-primary/10 rounded-lg text-primary border border-primary/20">
              <Check size={14} />
            </div>
            <h3 className="text-sm font-black uppercase tracking-widest text-foreground">Active Allocations</h3>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest mr-2">Inventory Status:</span>
            <span className="px-3 py-1 bg-card border border-border rounded-lg text-[10px] font-black text-primary shadow-sm">
              {gridRows.length} RECORDS TOTAL
            </span>
          </div>
        </div>
        <div className="h-[600px] bg-card">
          <DataGrid
            columns={gridColumns}
            rows={gridRows}
            rowKeyGetter={(r) => r.id}
            className="h-full border-none"
          />
        </div>
      </div>

      <HarmonyAlertDialog
        open={!!assignmentToComplete}
        onOpenChange={(open) => { if (!open) setAssignmentToComplete(null); }}
        title="Mark as Completed"
        description={`Mark ${assignmentToComplete?.name ?? "this employee"}'s work on this project as completed today? This will set the end date and cannot be undone.`}
        actionLabel="Mark Complete"
        onAction={() => { if (assignmentToComplete) completeMutation.mutate(assignmentToComplete); }}
        isActioning={completeMutation.isPending}
      />

      <HarmonyAlertDialog
        open={!!assignmentToDelete}
        onOpenChange={(open) => { if (!open) setAssignmentToDelete(null); }}
        variant="danger"
        title="Delete Assignment"
        description={`This will permanently remove ${assignmentToDelete?.name ?? "this assignment"} from the project. This action cannot be undone.`}
        actionLabel="Delete Assignment"
        onAction={() => { if (assignmentToDelete) deleteMutation.mutate(assignmentToDelete); }}
        isActioning={deleteMutation.isPending}
      />
    </div>
  );
};

export default Assignments;
